  const handleUpdateHost = (
    hostId: string,
    updatedFields: Partial<HostEmployee>,
  ) => {
    const currentHost = hosts.find((h) => h.id === hostId);
    if (!currentHost) return;

    const nextHost = { ...currentHost, ...updatedFields };

    hostsApi
      .update(hostId, nextHost)
      .then(() => {
        setHosts((prev) =>
          prev.map((h) => {
            if (h.id === hostId) {
              return nextHost;
            }
            return h;
          }),
        );
        customAlert("Data host berhasil diperbarui di database!");
        setTimeout(() => {}, 4000);
      })
      .catch((err) => {
        console.error("Gagal memperbarui host:", err);
        customAlert("Gagal memperbarui data host. Coba lagi.");
      });
  };

  const handleAvatarUpload = (hostId: string, file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        const MAX_SIZE = 200;
        let w = img.width;
        let h = img.height;
        if (w > MAX_SIZE || h > MAX_SIZE) {
          if (w > h) {
            h *= MAX_SIZE / w;
            w = MAX_SIZE;
          } else {
            w *= MAX_SIZE / h;
            h = MAX_SIZE;
          }
        }
        canvas.width = w;
        canvas.height = h;
        const ctx = canvas.getContext("2d");
        ctx?.drawImage(img, 0, 0, w, h);
        const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
        handleUpdateHost(hostId, { avatar: dataUrl });
      };
      if (typeof reader.result === "string") {
        img.src = reader.result;
      }
    };
    reader.readAsDataURL(file);
  };

