  const [reportingRawData, setReportingRawData] = useState<any[]>([]);
  const [reportingBrandChartRange, setReportingBrandChartRange] = useState<
    "7d" | "30d" | "90d"
  >("7d");
  const [skuRawData, setSkuRawData] = useState<any[]>([]);
  const [shopeeSkuLogs, setShopeeSkuLogs] = useState<any[]>([]);
  const [isDragOverReporting, setIsDragOverReporting] = useState(false);
  const [saveTargetBrandId, setSaveTargetBrandId] = useState("");
  const [saveTargetPlatform, setSaveTargetPlatform] = useState("TikTok Live");
  const [shopeeRawTab, setShopeeRawTab] = useState<
    "day" | "shift" | "dayOfWeek" | "raw"
  >("day");
  const [reportingShopeeRawTab, setReportingShopeeRawTab] = useState<
    "day" | "shift" | "dayOfWeek" | "raw"
  >("day");
  const reportingBrandChartGranularity = "Harian";
  const [adminReportBrandFilter, setAdminReportBrandFilter] = useState("");
  const [adminShiftChecklistObj, setAdminShiftChecklistObj] = useState<Record<string, string[]>>({});
  const adminShiftChecklist = adminShiftChecklistObj[adminReportBrandFilter || "default_brand"] || [];
  const setAdminShiftChecklist = (val: string[]) => {
    const newObj = { ...adminShiftChecklistObj, [adminReportBrandFilter || "default_brand"]: val };
    setAdminShiftChecklistObj(newObj);
  };

  useEffect(() => {
    if (!isGlobalConfigsLoaded) return;
    const timer = setTimeout(() => {
      saveLocalConfig({ adminShiftChecklistObj });

    }, 1000); // 1-second debounce
    return () => clearTimeout(timer);
  }, [adminShiftChecklistObj, isGlobalConfigsLoaded]);
  const [autoDetectNotice, setAutoDetectNotice] = useState("");
  const [isSavingReport, setIsSavingReport] = useState(false);

  const activeReportBrandTrendData = useMemo(() => {
    const grouped = new Map<
      string,
      { date: string; gmv: number; orders: number }
    >();

    reportingRawData.forEach((row) => {
      const normalized = normalizeDateYMD(
        String(
          row.date ||
            row.createdAt ||
            row.uploadedAt ||
            row.timestamp ||
            "",
        ),
      );
      if (!normalized) return;
      const current = grouped.get(normalized) || {
        date: normalized,
        gmv: 0,
        orders: 0,
      };
      current.gmv += Number(row.gmv) || 0;
      current.orders += Number(row.orders || row.buyers || 0) || 0;
      grouped.set(normalized, current);
    });

    const sorted = Array.from(grouped.values()).sort((a, b) =>
      a.date.localeCompare(b.date),
    );
    const limit =
      reportingBrandChartRange === "7d"
        ? 7
        : reportingBrandChartRange === "30d"
          ? 30
          : 90;
    return sorted.slice(Math.max(sorted.length - limit, 0));
  }, [reportingRawData, reportingBrandChartRange]);

  useEffect(() => {
    // --- ONE-TIME AUTO CLEANUP FOR BUGGED 2026-12-01 DATES ---
    // (Sekarang berbasis state lokal, bukan Firestore)
    setBrandPerformanceLogs((prev) => {
      const badIds = prev
        .filter((d) => {
          const date = d.date;
          return date && (date.includes('2026-12-') || date.includes('2026-11-') || date > '2026-06-30');
        })
        .map((d) => d.id);
      if (badIds.length > 0) {
        console.log(`Auto-cleaning ${badIds.length} bad future date records from state...`);
        return prev.filter((d) => !badIds.includes(d.id));
      }
      return prev;
    });
  }, []);


  const handleDeletePerformanceLog = async (
    id: string,
    brandName: string,
    date: string,
  ) => {
    requestConfirm(
      "Hapus Data Live Stream",
      `Apakah Anda yakin ingin menghapus catatan live stream brand ${brandName} tanggal ${date}?`,
      async () => {
        try {
          // Hapus dari state lokal
          setBrandPerformanceLogs((prev) => prev.filter((log) => log.id !== id));
          customAlert("Data live stream berhasil dihapus dari database!");
        } catch (err: any) {
          console.error("Gagal menghapus:", err);
          customAlert("Error: " + err.message);
        }
      },
      "danger",
    );
  };


  const handleUploadSkuRaw = (file: File) => {
    setAutoDetectNotice("");
    setUploadedFileName(file.name);

    // Auto-detect brand from filename
    let detectedBrandObj = null;
    const fileNameLower = file.name.toLowerCase();
    for (const b of clientBrands) {
      const brandNameClean = (b.name || "").toLowerCase().replace(/[^a-z0-9]/g, "");
      if (fileNameLower.includes(brandNameClean) && brandNameClean.length > 0) {
        detectedBrandObj = b;
        break;
      }
      const words = b.name
        .toLowerCase()
        .split(/\s+/)
        .filter((w) => w.length > 2);
      if (words?.some((word) => fileNameLower.includes(word))) {
        detectedBrandObj = b;
        break;
      }
    }

    if (detectedBrandObj) {
      setSaveTargetBrandId(detectedBrandObj.id);
    }
    setSaveTargetPlatform(
      fileNameLower.includes("tiktok") ? "TikTok Live" : "Shopee Live",
    );

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: "array", raw: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet, {
          header: 1,
        }) as any[];

        if (jsonData.length < 2) {
          alert("File kosong atau format salah.");
          return;
        }

        // Find headers
        let headerRowIdx = -1;
        for (let r = 0; r < Math.min(jsonData.length, 50); r++) {
          const row = jsonData[r] as any[];
          if (
            row &&
            row?.some(
              (cell) =>
                typeof cell === "string" &&
                (cell.toLowerCase().includes("sku") ||
                  cell.toLowerCase().includes("produk") ||
                  cell.toLowerCase().includes("product") ||
                  cell.toLowerCase().includes("item") ||
                  cell.toLowerCase().includes("judul")),
            )
          ) {
            headerRowIdx = r;
            break;
          }
        }
        if (headerRowIdx === -1) headerRowIdx = 0;

        let globalDateFallback = "";
        for (let r = 0; r < headerRowIdx; r++) {
          const row = jsonData[r] as any[];
          if (!row) continue;
          for (let i = 0; i < row.length; i++) {
            const cellStr = String(row[i] || "");
            const matchYMD = cellStr.match(/(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
            if (matchYMD) {
              globalDateFallback = `${matchYMD[1]}-${matchYMD[2]}-${matchYMD[3]}`;
              break;
            }
            const matchDMY = cellStr.match(/(\d{2})[\/\-](\d{2})[\/\-](\d{4})/);
            if (matchDMY) {
              globalDateFallback = `${matchDMY[3]}-${matchDMY[2]}-${matchDMY[1]}`;
              break;
            }
          }
          if (globalDateFallback) break;
        }
        if (!globalDateFallback) {
          const fnMatchYMD = file.name.match(/(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
          if (fnMatchYMD) globalDateFallback = `${fnMatchYMD[1]}-${fnMatchYMD[2]}-${fnMatchYMD[3]}`;
          else {
            const fnMatchYM = file.name.match(/(\d{4})[\/\-](\d{2})/);
            if (fnMatchYM) globalDateFallback = `${fnMatchYM[1]}-${fnMatchYM[2]}-01`;
          }
        }

        const headers = Array.from(jsonData[headerRowIdx] || []).map((h: any) =>
          String(h || "")
            .trim()
            .toLowerCase(),
        );

        let detectedPlatform = fileNameLower.includes("tiktok")
          ? "TikTok Live"
          : fileNameLower.includes("shopee")
            ? "Shopee Live"
            : "";
        if (!detectedPlatform) {
          if (
            headers?.some(
              (h) =>
                h.includes("tiktok") ||
                h.includes("attributed") ||
                h.includes("product impressions") ||
                h.includes("product clicks"),
            )
          ) {
            detectedPlatform = "TikTok Live";
          } else if (headers?.some((h) => h.includes("shopee"))) {
            detectedPlatform = "Shopee Live";
          }
        }
        if (detectedPlatform) {
          setSaveTargetPlatform(detectedPlatform);
        }

        let isMonthFirst = false;
        let shouldSwapExcelDates = false;
        let firstVals = new Set<number>();
        let secondVals = new Set<number>();
        let definiteMatchFound = false;

        for (let r = headerRowIdx + 1; r < jsonData.length; r++) {
          const row = jsonData[r] as any[];
          if (!row || row.length === 0) continue;
          let dtMatchStr = "";
          let rawStart: any = null;
          headers.forEach((h, idx) => {
            if (
              h.includes("tanggal") ||
              h.includes("waktu") ||
              h.includes("date") ||
              h.includes("start time") ||
              h.includes("start") ||
              h.includes("time") ||
              h.includes("periode")
            ) {
              rawStart = row[idx];
              dtMatchStr = String(row[idx]);
            }
          });

          if (rawStart && typeof rawStart === "number") {
            const dateObj = XLSX.SSF.parse_date_code(rawStart);
            firstVals.add(dateObj.d);
            secondVals.add(dateObj.m);
            if (dateObj.d > 12) {
              shouldSwapExcelDates = false;
              definiteMatchFound = true;
            } else if (dateObj.m > 12) {
              shouldSwapExcelDates = true;
              definiteMatchFound = true;
            }
          } else if (dtMatchStr && typeof dtMatchStr === "string") {
            const allMatches = dtMatchStr.match(/\b(\d{1,4})[\/\-](\d{1,2})[\/\-](\d{1,4})\b/g);
            if (allMatches) {
              for (const matchStr of allMatches) {
                const dtSplit = matchStr.split(/[\/\-]/);
                if (dtSplit.length === 3) {
                  let firstStr = dtSplit[0];
                  let secondStr = dtSplit[1];
                  if (dtSplit[0].length === 4) {
                    firstStr = dtSplit[1];
                    secondStr = dtSplit[2];
                  }
                  const first = parseInt(firstStr, 10);
                  const second = parseInt(secondStr, 10);
                  if (!isNaN(first) && !isNaN(second)) {
                    firstVals.add(first);
                    secondVals.add(second);
                    if (first > 12) {
                      isMonthFirst = false; // DD/MM
                      shouldSwapExcelDates = false;
                      definiteMatchFound = true;
                    } else if (second > 12) {
                      isMonthFirst = true; // MM/DD
                      shouldSwapExcelDates = true;
                      definiteMatchFound = true;
                    }
                  }
                }
              }
            }
          }
        }

        if (!definiteMatchFound) {
          isMonthFirst = false;
          shouldSwapExcelDates = false;
        }

        const parseDate = (val: any) => {
          if (!val) return "";
          if (typeof val === "number") {
            const dateObj = XLSX.SSF.parse_date_code(val);
            const y = dateObj.y;
            let m = dateObj.m;
            let d = dateObj.d;
            if (shouldSwapExcelDates) {
              const temp = m;
              m = d;
              d = temp;
            }
            const mStr = String(m).padStart(2, "0");
            const dStr = String(d).padStart(2, "0");
            return `${y}-${mStr}-${dStr}`;
          }
          let str = String(val).trim();
          let match = str.match(/(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
          if (match) {
            let dStr = match[3];
            let mStr = match[2];
            return `${match[1]}-${mStr.padStart(2, "0")}-${dStr.padStart(2, "0")}`;
          }
          match = str.match(/(\d{2})[\/\-](\d{2})[\/\-](\d{4})/);
          if (match) {
            let dStr, mStr;
            if (isMonthFirst) {
              mStr = match[1];
              dStr = match[2];
            } else {
              dStr = match[1];
              mStr = match[2];
            }
            return `${match[3]}-${mStr.padStart(2, "0")}-${dStr.padStart(2, "0")}`;
          }
          return str;
        };

        const parseNum = (val: any) => {
          if (!val) return 0;
          if (typeof val === "number") return val;
          let s = String(val)
            .trim()
            .replace(/Rp|rp|IDR|idr|\s/g, "");
          if (
            s.indexOf(",") === -1 &&
            s.indexOf(".") !== -1 &&
            s.split(".").length > 2
          ) {
            s = s.replace(/\./g, "");
          } else if (s.indexOf(",") !== -1 && s.indexOf(".") !== -1) {
            if (s.indexOf(",") < s.indexOf(".")) {
              s = s.replace(/,/g, "");
            } else {
              s = s.replace(/\./g, "").replace(/,/g, ".");
            }
          } else if (s.indexOf(",") !== -1 && s.indexOf(".") === -1) {
            s = s.replace(/,/g, ".");
          } else if (
            s.indexOf(".") !== -1 &&
            s.split(".").length === 2 &&
            s.split(".")[1].length === 3
          ) {
            s = s.replace(/\./g, "");
          }
          return Number(s.replace(/[^0-9.-]+/g, ""));
        };

        const parsedData = [];
        for (let i = headerRowIdx + 1; i < jsonData.length; i++) {
          const row = jsonData[i] as any[];
          if (!row || row.length === 0) continue;

          let sku = "",
            productName = "",
            sold = 0,
            revenue = 0,
            clicks = 0,
            cartAdds = 0,
            date = "";

          headers.forEach((h, idx) => {
            const val = row[idx];
            if (!val) return;
            if (
              h.includes("nama produk") ||
              h.includes("product name") ||
              h.includes("judul produk") ||
              h.includes("item name") ||
              h.includes("nama item") ||
              h === "produk" ||
              h === "product" ||
              h.includes("product list") ||
              h.includes("title")
            )
              productName = String(val);
            else if (
              h.includes("sku") ||
              h.includes("induk") ||
              h.includes("product id") ||
              h.includes("item id")
            )
              sku = String(val);
            else if (
              h.includes("produk terjual(pesanan dibayar)") ||
              h.includes("produk terjual (pesanan dibayar)") ||
              h.includes("jumlah terjual") ||
              h.includes("items sold") ||
              h.includes("produk terjual(pesanan dibuat)") ||
              h.includes("attributed items sold") ||
              h.includes("barang terjual") ||
              h.includes("units sold")
            )
              sold = parseNum(val);
            else if (
              h.includes("penjualan(pesanan dibayar)") ||
              h.includes("penjualan (pesanan dibayar)") ||
              h.includes("revenue") ||
              h.includes("gmv") ||
              h.includes("penjualan(pesanan dibuat)") ||
              h.includes("penjualan (idr)") ||
              h.includes("attributed gmv") ||
              h.includes("pendapatan") ||
              h.includes("sales")
            )
              revenue = parseNum(val);
            else if (
              h.includes("klik produk") ||
              h.includes("product clicks") ||
              h.includes("clicks")
            )
              clicks = parseNum(val);
            else if (
              h.includes("tambah ke keranjang") ||
              h.includes("add to cart") ||
              h.includes("keranjang")
            )
              cartAdds = parseNum(val);
            else if (
              h.includes("tanggal") ||
              h.includes("waktu") ||
              h.includes("date") ||
              h.includes("start time") ||
              h.includes("start") ||
              h.includes("time") ||
              h.includes("periode")
            )
              date = parseDate(val);
            // Fallbacks for Shopee export
            else if (
              h.includes("pesanan dibayar") ||
              h.includes("orders paid") ||
              h.includes("pesanan(pesanan dibuat)")
            ) {
              if (sold === 0) sold = parseNum(val);
            } else if (h.includes("sales") || h.includes("penjualan")) {
              if (revenue === 0) revenue = parseNum(val);
            }
          });

          if (productName || sku) {
            parsedData.push({
              id: `sku_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
              sku: sku || "N/A",
              productName: productName || "Unnamed Product",
              sold: sold,
              revenue: revenue,
              clicks,
              cartAdds,
              sourceKind: getProductSourceKind(detectedPlatform),
              date: date || globalDateFallback || new Date().toISOString().split("T")[0],
            });
          }
        }

        setSkuRawData(parsedData);
        if (detectedBrandObj) {
          setAutoDetectNotice(
            `Auto-detected Klien: ${detectedBrandObj.name} (${parsedData.length} records).`,
          );
        }
      } catch (err) {
        console.error(err);
        alert("Error: " + err);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handleUploadReportingRaw = (file: File) => {
    setAutoDetectNotice("");
    setUploadedFileName(file.name);
    const fileNameLower = file.name.toLowerCase();

    // 1. Auto-detect platform from filename
    let detectedPlatform = "";
    if (fileNameLower.includes("tiktok")) {
      detectedPlatform = "TikTok Live";
    } else if (fileNameLower.includes("shopee")) {
      detectedPlatform = "Shopee Live";
    } else if (
      fileNameLower.includes("tokopedia") ||
      fileNameLower.includes("tokoped")
    ) {
      detectedPlatform = "Tokopedia";
    } else if (
      fileNameLower.includes("lazada") ||
      fileNameLower.includes("laz")
    ) {
      detectedPlatform = "Lazada";
    }

    // 2. Auto-detect brand from filename
    let detectedBrandObj = null;
    for (const b of clientBrands) {
      const brandNameClean = (b.name || "").toLowerCase().replace(/[^a-z0-9]/g, "");
      // Direct clean substring
      if (fileNameLower.includes(brandNameClean) && brandNameClean.length > 0) {
        detectedBrandObj = b;
        break;
      }
      // Word by word matching for longer names
      const words = b.name
        .toLowerCase()
        .split(/\s+/)
        .filter((w) => w.length > 2);
      if (words?.some((word) => fileNameLower.includes(word))) {
        detectedBrandObj = b;
        break;
      }
    }

    if (detectedPlatform) {
      setSaveTargetPlatform(detectedPlatform);
    }
    if (detectedBrandObj) {
      setSaveTargetBrandId(detectedBrandObj.id);
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: "array", raw: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet, {
          header: 1,
        }) as any[];

        if (jsonData.length < 2) {
          alert("File kosong atau format salah.");
          return;
        }

        // Find headers row and map columns
        let headerRowIdx = -1;
        for (let r = 0; r < Math.min(jsonData.length, 50); r++) {
          const row = jsonData[r];
          if (
            row &&
            row?.some((cell) => {
              if (typeof cell !== "string") return false;
              const cLower = cell.toLowerCase().trim();
              // Filter out row 0 main grouping titles
              if (
                cLower === "interaksi" ||
                cLower === "promosi" ||
                cLower === "konversi" ||
                cLower === "data utama"
              ) {
                const nonEmpStrCols = row.filter(
                  (c) => typeof c === "string" && c.trim().length > 0,
                ).length;
                if (nonEmpStrCols < 8) return false;
              }
              return (
                cLower.includes("streaming") ||
                cLower.includes("mulai") ||
                cLower.includes("gmv") ||
                cLower.includes("user id") ||
                cLower === "penonton" ||
                cLower === "penonton aktif" ||
                cLower === "suka" ||
                cLower === "komentar" ||
                cLower.includes("pembeli(pesanan")
              );
            })
          ) {
            headerRowIdx = r;
            break;
          }
        }

        if (headerRowIdx === -1) {
          headerRowIdx = 0; // fallback to first row
        }

        const headers = Array.from(jsonData[headerRowIdx] || []).map((h: any) =>
          String(h || "")
            .trim()
            .toLowerCase(),
        );

        let detectedPlatform = fileNameLower.includes("tiktok")
          ? "TikTok Live"
          : fileNameLower.includes("shopee")
            ? "Shopee Live"
            : "";
        if (!detectedPlatform) {
          if (
            headers?.some(
              (h) =>
                h.includes("tiktok") ||
                h.includes("attributed") ||
                h.includes("product impressions") ||
                h.includes("product clicks"),
            )
          ) {
            detectedPlatform = "TikTok Live";
          } else if (headers?.some((h) => h.includes("shopee"))) {
            detectedPlatform = "Shopee Live";
          }
        }
        if (detectedPlatform) {
          setSaveTargetPlatform(detectedPlatform);
        }

        // Help detect platform from columns if not detected yet
        if (!detectedPlatform) {
          if (
            headers?.some(
              (h) =>
                h.includes("tiktok") ||
                h.includes("live room") ||
                h.includes("judul ruang live") ||
                h.includes("highest ccu") ||
                h.includes("penonton serentak tertinggi") ||
                h.includes("anchor") ||
                h.includes("uid") ||
                h.includes("live impressions") ||
                h.includes("attributed gmv") ||
                h.includes("product impressions"),
            )
          ) {
            detectedPlatform = "TikTok Live";
            setSaveTargetPlatform(detectedPlatform);
          } else if (
            headers?.some(
              (h) =>
                h.includes("shopee") ||
                h.includes("username pembeli") ||
                h.includes("live id") ||
                h.includes("nama produk") ||
                h.includes("nama livestream") ||
                h.includes("livestream name") ||
                h.includes("tambah ke keranjang") ||
                h.includes("penonton aktif") ||
                h.includes("pesanan(pesanan dibuat)") ||
                h.includes("max concurrent viewers") ||
                h.includes("orders(orders paid)"),
            )
          ) {
            detectedPlatform = "Shopee Live";
            setSaveTargetPlatform(detectedPlatform);
          }
        }

        // Prepare info banner
        const parts = [];
        if (detectedBrandObj) parts.push(`Klien: ${detectedBrandObj.name}`);
        if (detectedPlatform) parts.push(`Platform: ${detectedPlatform}`);

        if (parts.length > 0) {
          setAutoDetectNotice(
            `Auto-detection Pintar: Berhasil mendeteksi ${parts.join(" & ")} dari nama file/kolom (${file.name})!`,
          );
        } else {
          setAutoDetectNotice(
            `File "${file.name}" berhasil dibaca. Silakan pilih Brand & Platform secara manual.`,
          );
        }

        // Helper to find indices
        const findColIdx = (aliases: string[]) => {
          // 1st pass: exact match (prioritize the first alias in the list)
          for (const alias of aliases) {
            const idx = headers.findIndex((h) => h === alias);
            if (idx !== -1) return idx;
          }
          // 2nd pass: partial match
          for (const alias of aliases) {
            const idx = headers.findIndex((h) => h.includes(alias));
            if (idx !== -1) return idx;
          }
          return -1;
        };

        const shopeeSourceKind =
          detectedPlatform === "Shopee Live"
            ? uploadTargetTab === "engagement"
              ? "engagement"
              : inferShopeeReportingKind(headers, fileNameLower)
            : "live";

        if (detectedPlatform === "Shopee Live") {
          setUploadTargetTab(shopeeSourceKind as "live" | "engagement");
        }

        const titleIdx = findColIdx(
          detectedPlatform === "Shopee Live" && shopeeSourceKind === "engagement"
            ? [
                "user id",
                "userid",
                "periode data",
                "periode",
                "tanggal",
                "date",
                "nama livestream",
                "livestream name",
                "live room title",
                "room title",
                "judul ruang live",
                "judul",
                "livestream",
                "streaming",
                "live",
              ]
            : [
                "nama livestream",
                "livestream name",
                "live room title",
                "room title",
                "judul ruang live",
                "judul",
                "livestream",
                "streaming",
                "live",
                "nama_brand",
                "brand",
              ],
        );
        const userIdIdx = findColIdx(["user id", "userid", "uid"]);
        const periodIdx = findColIdx(["periode data", "periode", "period"]);
        const startIdx = findColIdx([
          "start time",
          "waktu mulai",
          "tanggal",
          "date",
          "waktu",
          "mulai",
          "start",
          "periode data",
          "periode",
        ]);
        const durationIdx = findColIdx([
          "durasi",
          "duration",
          "lama",
          "waktu streaming",
        ]);
        const gmvIdx = findColIdx([
          "penjualan(pesanan siap dikirim)",
          "penjualan(pesanan dibuat)",
          "sales(orders paid)",
          "sales(orders created)",
          "penjualan",
          "attributed gmv",
          "gmv",
          "perolehan",
          "omset",
          "revenue",
          "pendapatan",
          "gross profit",
          "gross revenue",
          "total sales",
        ]);
        const productIdx = findColIdx([
          "produk terjual(pesanan siap dikirim)",
          "produk terjual(pesanan dibuat)",
          "items sold(orders paid)",
          "items sold(orders created)",
          "produk terjual",
          "attributed items sold",
          "unit terjual",
          "produk",
          "product",
          "terjual",
          "item",
          "items sold",
          "items",
        ]);
        const buyerIdx = findColIdx([
          "pembeli(pesanan siap dikirim)",
          "pembeli(pesanan dibuat)",
          "pembeli",
          "buyers(orders paid)",
          "buyers(orders created)",
          "buyers",
          "customers",
          "customer",
          "buyer",
          "pelanggan",
        ]);
        const aovIdx = findColIdx([
          "avg. price",
          "sales per buyer(orders paid)",
          "sales per buyer(orders created)",
          "sales per buyer",
          "aov",
          "average order value",
          "rata-rata",
          "order value",
        ]);
        const viewsIdx = findColIdx([
          "dilihat",
          "views",
          "view",
        ]);
        const impressionsIdx = findColIdx([
          "dilihat",
          "total viewers",
          "live impressions",
          "tayangan live",
          "impression",
          "tayangan",
          "visitor",
          "traffic",
          "pemirsa",
          "exposure",
          "viewers",
        ]);
        const penontonIdx = findColIdx([
          "penonton",
          "unique viewers",
          "viewer",
        ]);
        const liveVisitsIdx = findColIdx([
          "penonton aktif",
          "max concurrent viewers",
          "viewers(max concurrent)",
          "viewers(max co-current)",
          "highest ccu",
          "penonton serentak tertinggi",
          "live visits",
          "kunjungan live",
          "engaged viewers",
          "active viewers",
        ]);
        const productImpressionsIdx = findColIdx([
          "tayangan produk",
          "product views",
          "product impression",
          "product impressions",
        ]);
        const avgViewDurationIdx = findColIdx([
          "rata-rata durasi ditonton",
          "durasi ditonton",
          "durasi rata-rata menonton",
          "avg. watch duration",
          "average watch time",
          "watch duration",
          "avg view",
          "average view",
          "rata-rata menonton",
          "rata rata menonton",
          "waktu menonton",
          "rata-rata view",
          "avg. viewing duration",
          "avg viewing duration",
          "viewing duration",
        ]);
        const clicksIdx = findColIdx([
          "tambah ke keranjang",
          "add to cart",
          "keranjang",
          "product clicks",
          "klik produk",
          "clicks",
          "click",
          "klik",
          "kunjungan",
          "detail",
          "buka",
        ]);
        const ordersIdx = findColIdx([
          "pesanan(pesanan siap dikirim)",
          "pesanan(pesanan dibuat)",
          "orders(orders paid)",
          "orders(orders created)",
          "pesanan",
          "attributed sku orders",
          "attributed orders",
          "orders",
          "created",
          "buat pesanan",
          "order created",
          "pesanan dibuat",
        ]);
        const followersIdx = findColIdx([
          "pengikut baru dari livestream",
          "pengikut baru",
          "new followers",
          "pengikut",
          "follower",
          "followers",
          "fans",
        ]);
        const likesIdx = findColIdx(["suka", "likes", "like", "love"]);
        const sharesIdx = findColIdx([
          "dibagikan",
          "share",
          "shares",
          "bagikan",
          "sebar",
        ]);
        const commentsIdx = findColIdx([
          "komentar",
          "comment",
          "komen",
          "comments",
        ]);
        const peakViewersIdx = findColIdx([
          "penonton tertinggi",
          "peak viewers",
          "highest viewers",
        ]);
        const shopVouchersIdx = findColIdx([
          "voucher toko diklaim",
          "shop voucher claimed",
        ]);
        const specialVouchersIdx = findColIdx([
          "voucher spesial live diklaim",
          "special live voucher claimed",
        ]);
        const coinsClaimedIdx = findColIdx(["koin diklaim", "coins claimed"]);

        const parseIndonesianNumber = (val: any): number => {
          if (val === undefined || val === null || val === "-" || val === "")
            return 0;
          if (typeof val === "number") return val;

          let str = String(val)
            .replace(/rp/gi, "")
            .replace(/\s/g, "")
            .trim()
            .toLowerCase();

          // handle metric suffixes
          let multiplier = 1;
          if (str.endsWith("k") || str.endsWith("rb") || str.endsWith("ribu")) {
            multiplier = 1000;
            str = str.replace(/(k|rb|ribu)$/, "");
          } else if (
            str.endsWith("m") ||
            str.endsWith("jt") ||
            str.endsWith("juta")
          ) {
            multiplier = 1000000;
            str = str.replace(/(m|jt|juta)$/, "");
          } else if (str.endsWith("b") || str.endsWith("miliar")) {
            multiplier = 1000000000;
            str = str.replace(/(b|miliar)$/, "");
          }

          const isNegative = str.includes("-");

          if (str.includes(".") && str.includes(",")) {
            const lastComma = str.lastIndexOf(",");
            const lastDot = str.lastIndexOf(".");
            if (lastComma > lastDot) {
              str = str.replace(/\./g, "").replace(",", ".");
            } else {
              str = str.replace(/,/g, "");
            }
          } else if (str.includes(",")) {
            if (str.indexOf(",") !== str.lastIndexOf(",")) {
              str = str.replace(/,/g, "");
            } else {
              if (/,\d{3}$/.test(str)) {
                str = str.replace(/,/g, "");
              } else {
                str = str.replace(",", ".");
              }
            }
          } else if (str.includes(".")) {
            if (str.indexOf(".") !== str.lastIndexOf(".")) {
              str = str.replace(/\./g, "");
            } else {
              if (/\.\d{3}$/.test(str)) {
                str = str.replace(/\./g, "");
              }
            }
          }

          str = str.replace(/[^0-9.]/g, "");
          const parsed = parseFloat(str) * (isNegative ? -1 : 1);
          return (isNaN(parsed) ? 0 : parsed) * multiplier;
        };

        // Heuristic detection: check if string dates are MM/DD or DD/MM
        let isMonthFirst = false; // assume DD/MM/YYYY by default
        let shouldSwapExcelDates = false;
        let firstVals = new Set<number>();
        let secondVals = new Set<number>();
        let definiteMatchFound = false;

        for (let r = headerRowIdx + 1; r < jsonData.length; r++) {
          const rowData = jsonData[r] as any[];
          if (!rowData || rowData.length === 0) continue;
          const rawStart = rowData[startIdx !== -1 ? startIdx : 0];

          if (rawStart && typeof rawStart === "number") {
            const dateObj = XLSX.SSF.parse_date_code(rawStart);
            firstVals.add(dateObj.d);
            secondVals.add(dateObj.m);
            if (dateObj.d > 12) {
              shouldSwapExcelDates = false;
              definiteMatchFound = true;
            } else if (dateObj.m > 12) {
              shouldSwapExcelDates = true;
              definiteMatchFound = true;
            }
          } else if (rawStart && typeof rawStart === "string") {
            const allMatches = rawStart.match(/\b(\d{1,4})[\/\-](\d{1,2})[\/\-](\d{1,4})\b/g);
            if (allMatches) {
              for (const matchStr of allMatches) {
                const dtSplit = matchStr.split(/[\/\-]/);
                if (dtSplit.length === 3) {
                  let firstStr = dtSplit[0];
                  let secondStr = dtSplit[1];
                  let checkIdx1 = 0;
                  let checkIdx2 = 1;
                  if (dtSplit[0].length === 4) {
                    firstStr = dtSplit[1];
                    secondStr = dtSplit[2];
                    checkIdx1 = 1;
                    checkIdx2 = 2;
                  }
                  const first = parseInt(firstStr, 10);
                  const second = parseInt(secondStr, 10);
                  if (!isNaN(first) && !isNaN(second)) {
                    firstVals.add(first);
                    secondVals.add(second);
                    if (first > 12) {
                      isMonthFirst = false; // DD/MM (or YYYY/MM/DD if 4 length)
                      shouldSwapExcelDates = false;
                      definiteMatchFound = true;
                    } else if (second > 12) {
                      isMonthFirst = true; // MM/DD (or swapped YYYY/DD/MM)
                      shouldSwapExcelDates = true;
                      definiteMatchFound = true;
                    }
                  }
                }
              }
            }
          }
        }

        if (!definiteMatchFound) {
          isMonthFirst = false;
          shouldSwapExcelDates = false;
        }

        const rows: any[] = [];
        const isShopeeEngagement =
          detectedPlatform === "Shopee Live" && shopeeSourceKind === "engagement";
        for (let r = headerRowIdx + 1; r < jsonData.length; r++) {
          const rowData = jsonData[r] as any[];
          // Skip completely empty rows
          if (!rowData || rowData.length === 0) continue;

          const titleRaw =
            detectedPlatform === "Shopee Live" && shopeeSourceKind === "engagement"
              ? String(
                  rowData[userIdIdx !== -1 ? userIdIdx : periodIdx !== -1 ? periodIdx : titleIdx] ||
                    rowData[titleIdx] ||
                    "",
                )
              : titleIdx !== -1
                ? String(rowData[titleIdx] || "")
                : String(rowData[0] || "");
          // Identify "Total" or summary rows which shouldn't be counted as individual streams
          if (
            titleRaw.toLowerCase() === "total" ||
            titleRaw.toLowerCase().includes("ringkasan") ||
            titleRaw.toLowerCase() === "summary"
          ) {
            continue; // Skip total aggregated row from export files
          }
          if (titleIdx !== -1 && !rowData[titleIdx]) continue; // Skip if title column is mapped but it's empty

          const title = titleRaw || `Stream ${r}`;
          const rawStart = rowData[startIdx !== -1 ? startIdx : 0];

          let formattedDate = "";
          let shift = "Shift Lainnya";
          if (rawStart) {
            if (typeof rawStart === "number") {
              const dateObj = XLSX.SSF.parse_date_code(rawStart);
              const y = dateObj.y;
              let m = dateObj.m;
              let d = dateObj.d;
              if (shouldSwapExcelDates) {
                const temp = m;
                m = d;
                d = temp;
              }
              const mStr = String(m).padStart(2, "0");
              const dStr = String(d).padStart(2, "0");
              const hh = String(dateObj.H).padStart(2, "0");
              const mm = String(dateObj.M).padStart(2, "0");
              formattedDate = `${y}-${mStr}-${dStr} ${hh}:${mm}`;

              const hour = parseInt(hh, 10);
              const matchedShift = getShiftFromHour(hour, shifts);
              if (matchedShift) shift = matchedShift;
            } else {
              formattedDate = String(rawStart).trim();

              // Normalize DD/MM/YYYY or MM/DD/YYYY or DD-MM-YYYY to YYYY-MM-DD
              if (
                formattedDate.indexOf("/") !== -1 ||
                (formattedDate.indexOf("-") !== -1 &&
                  formattedDate.split("-")[0].length <= 2)
              ) {
                const dtSplitRegex = formattedDate
                  .split(" ")[0]
                  .split(/[\/\-]/);
                if (dtSplitRegex.length === 3) {
                  const timeMatchList = formattedDate.match(
                    /\d{1,2}:\d{2}(:\d{2})?/,
                  );
                  const tmPart = timeMatchList ? timeMatchList[0] : "";
                  let y =
                    dtSplitRegex[2].length === 2
                      ? `20${dtSplitRegex[2]}`
                      : dtSplitRegex[2];

                  let m, d;
                  if (isMonthFirst) {
                    m = String(dtSplitRegex[0]).padStart(2, "0");
                    d = String(dtSplitRegex[1]).padStart(2, "0");
                  } else {
                    m = String(dtSplitRegex[1]).padStart(2, "0");
                    d = String(dtSplitRegex[0]).padStart(2, "0");
                  }

                  if (dtSplitRegex[0].length === 4) {
                    y = dtSplitRegex[0];
                    if (isMonthFirst) {
                      m = String(dtSplitRegex[1]).padStart(2, "0");
                      d = String(dtSplitRegex[2]).padStart(2, "0");
                    } else {
                      m = String(dtSplitRegex[1]).padStart(2, "0");
                      d = String(dtSplitRegex[2]).padStart(2, "0");
                    }
                  }
                  formattedDate = `${y}-${m}-${d} ${tmPart}`.trim();
                }
              }

              const timeMatch = formattedDate.match(/(\d{1,2}:\d{2})/);
              if (timeMatch) {
                const hour = parseInt(timeMatch[1], 10);
                if (!isNaN(hour)) {
                  const matchedShift = getShiftFromHour(hour, shifts);
                  if (matchedShift) shift = matchedShift;
                }
              }
            }
          }

          const dateOnly = formattedDate.split(" ")[0] || formattedDate;

          const parsedImpressions =
            impressionsIdx !== -1
              ? parseIndonesianNumber(rowData[impressionsIdx])
              : 0;
          const parsedViews =
            viewsIdx !== -1
              ? parseIndonesianNumber(rowData[viewsIdx])
              : 0;
          const parsedPenonton =
            penontonIdx !== -1
              ? parseIndonesianNumber(rowData[penontonIdx])
              : 0;
          const parsedLiveVisits =
            liveVisitsIdx !== -1
              ? parseIndonesianNumber(rowData[liveVisitsIdx])
              : 0;
          const parsedProductImpressions =
            productImpressionsIdx !== -1
              ? parseIndonesianNumber(rowData[productImpressionsIdx])
              : 0;
          const parsedClicks =
            clicksIdx !== -1 ? parseIndonesianNumber(rowData[clicksIdx]) : 0;
          const parsedOrders =
            ordersIdx !== -1 ? parseIndonesianNumber(rowData[ordersIdx]) : 0;
          const liveGmv = gmvIdx !== -1 ? parseIndonesianNumber(rowData[gmvIdx]) : 0;

          let buyers =
            buyerIdx !== -1
              ? parseIndonesianNumber(rowData[buyerIdx])
              : parsedOrders;
          // Use parsedOrders as fallback for buyers since Shopee reports often lack an explicit buyers column

          const aov =
            aovIdx !== -1
              ? parseIndonesianNumber(rowData[aovIdx])
              : buyers > 0
                ? liveGmv / buyers
                : 0;

          const parsedFollowers =
            followersIdx !== -1
              ? parseIndonesianNumber(rowData[followersIdx])
              : 0;
          const parsedLikes =
            likesIdx !== -1 ? parseIndonesianNumber(rowData[likesIdx]) : 0;
          const parsedShares =
            sharesIdx !== -1 ? parseIndonesianNumber(rowData[sharesIdx]) : 0;
          const parsedComments =
            commentsIdx !== -1
              ? parseIndonesianNumber(rowData[commentsIdx])
              : 0;

          const parsedPeakViewers =
            peakViewersIdx !== -1
              ? parseIndonesianNumber(rowData[peakViewersIdx])
              : 0;
          const parsedShopVouchers =
            shopVouchersIdx !== -1
              ? parseIndonesianNumber(rowData[shopVouchersIdx])
              : 0;
          const parsedSpecialVouchers =
            specialVouchersIdx !== -1
              ? parseIndonesianNumber(rowData[specialVouchersIdx])
              : 0;
          const parsedCoinsClaimed =
            coinsClaimedIdx !== -1
              ? parseIndonesianNumber(rowData[coinsClaimedIdx])
              : 0;
          const rawAvgViewDuration =
            avgViewDurationIdx !== -1 ? rowData[avgViewDurationIdx] : "";
          let parsedAvgViewDuration = 0;
          if (typeof rawAvgViewDuration === "number") {
            if (rawAvgViewDuration > 0 && rawAvgViewDuration < 1) {
              // Excel time serial stored as fraction of a day
              parsedAvgViewDuration = Math.round(rawAvgViewDuration * 86400);
            } else {
              parsedAvgViewDuration = Math.round(rawAvgViewDuration);
            }
          } else {
            const rawAvgViewDurationStr = String(rawAvgViewDuration || "").trim();
            if (rawAvgViewDurationStr.includes(":")) {
              const parts = rawAvgViewDurationStr.split(":").map(Number);
              if (parts.length === 3) {
                parsedAvgViewDuration =
                  parts[0] * 3600 + parts[1] * 60 + parts[2];
              } else if (parts.length === 2) {
                parsedAvgViewDuration = parts[0] * 60 + parts[1];
              }
            } else {
              const numericAvgViewDuration =
                parseFloat(rawAvgViewDurationStr.replace(/[^0-9.]/g, "")) || 0;
              if (numericAvgViewDuration > 0 && numericAvgViewDuration < 1) {
                parsedAvgViewDuration = Math.round(
                  numericAvgViewDuration * 86400,
                );
              } else {
                parsedAvgViewDuration = Math.round(numericAvgViewDuration);
              }
            }
          }

          const impressions = parsedImpressions || 0;
          const views = parsedViews || parsedImpressions || 0;
          const penonton = parsedPenonton || parsedImpressions || 0;
          const followers = parsedFollowers || 0;
          const likes = parsedLikes || 0;
          const shares = parsedShares || 0;
          const comments = parsedComments || 0;
          const peakViewers = parsedPeakViewers || 0;
          const shopVouchers = parsedShopVouchers || 0;
          const specialVouchers = parsedSpecialVouchers || 0;
          const coinsClaimed = parsedCoinsClaimed || 0;

          const engagementRow = {
            title,
            sourceKind: "shopee_engagement",
            date: dateOnly,
            dateTime: formattedDate,
            shift,
            duration: 0,
            gmv: 0,
            products_sold: 0,
            buyers: 0,
            aov: 0,
            views,
            impressions,
            penonton,
            liveVisits: 0,
            productImpressions: 0,
            clicks: 0,
            orders: 0,
            followers,
            likes,
            shares,
            comments,
            avgViewDuration: parsedAvgViewDuration || 0,
            peakViewers,
            shopVouchers,
            specialVouchers,
            coinsClaimed,
            hasFunnelInFile: false,
          };

          const liveDuration = (() => {
            if (durationIdx === -1) return 0;
            const rawDurationValue = rowData[durationIdx];
            if (typeof rawDurationValue === "number") {
              if (rawDurationValue > 0 && rawDurationValue < 1) {
                return Math.round(rawDurationValue * 86400);
              }
              return Math.max(0, rawDurationValue);
            }

            const rawDur = String(rawDurationValue || "")
              .trim()
              .toLowerCase();
            const unitDurationMatch = rawDur.match(
              /^(?:(\d+(?:[.,]\d+)?)\s*h)?\s*(?:(\d+(?:[.,]\d+)?)\s*m)?\s*(?:(\d+(?:[.,]\d+)?)\s*s)?$/,
            );
            if (
              unitDurationMatch &&
              (unitDurationMatch[1] ||
                unitDurationMatch[2] ||
                unitDurationMatch[3])
            ) {
              const parseDurationPart = (value?: string) =>
                Number(String(value || "0").replace(",", ".")) || 0;
              return Math.round(
                parseDurationPart(unitDurationMatch[1]) * 3600 +
                  parseDurationPart(unitDurationMatch[2]) * 60 +
                  parseDurationPart(unitDurationMatch[3]),
              );
            }
            if (rawDur.includes(":")) {
              const parts = rawDur.split(":").map(Number);
              if (parts.length === 3) {
                return parts[0] * 3600 + parts[1] * 60 + parts[2];
              }
              if (parts.length === 2) {
                return parts[0] * 60 + parts[1];
              }
            } else {
              const safeFloat = parseFloat(rawDur.replace(/,/g, "."));
              if (!isNaN(safeFloat)) {
                if (safeFloat > 0 && safeFloat < 1.0) {
                  return Math.round(safeFloat * 86400);
                }
                return safeFloat;
              }
            }
            return 0;
          })();

          const liveAvgViewDuration = parsedAvgViewDuration;

          const liveRow = {
            title,
            sourceKind:
              detectedPlatform === "Shopee Live"
                ? `shopee_${shopeeSourceKind}`
                : `tiktok_${uploadTargetTab}`,
            date: dateOnly,
            dateTime: formattedDate,
            shift,
            duration: liveDuration,
            gmv: liveGmv,
            products_sold:
              productIdx !== -1 ? parseIndonesianNumber(rowData[productIdx]) : 0,
            buyers,
            aov:
              aovIdx !== -1
                ? parseIndonesianNumber(rowData[aovIdx])
                : buyers > 0
                  ? liveGmv / buyers
                  : 0,
            views,
            impressions,
            penonton,
            liveVisits: parsedLiveVisits || 0,
            productImpressions: parsedProductImpressions || 0,
            clicks: parsedClicks || 0,
            orders: parsedOrders || 0,
            followers,
            likes,
            shares,
            comments,
            avgViewDuration: liveAvgViewDuration || 0,
            peakViewers,
            shopVouchers,
            specialVouchers,
            coinsClaimed,
            hasFunnelInFile:
              parsedImpressions > 0 || parsedClicks > 0 || parsedOrders > 0,
          };

          rows.push(isShopeeEngagement ? engagementRow : liveRow);
        }

        setReportingRawData(rows);
      } catch (err) {
        console.error("Error parsing workbook:", err);
        alert(
          "Gagal membaca file excel. Silakan periksa kembali format file anda.",
        );
      }
    };
    reader.readAsArrayBuffer(file);
  };

