                                      const [y, m, d] = datePart.split("-");
                                      const dateObj = new Date(parseInt(y), parseInt(m) - 1, parseInt(d));
                                      if (isNaN(dateObj.getTime())) return raw;
                                      const dayName = dateObj.toLocaleDateString("id-ID", { weekday: "long" });
