                                if (editingAdminId) {
                                  setAdminAccounts(
                                    adminAccounts.map((a) =>
                                      a.id === editingAdminId
                                        ? {
                                            ...a,
                                            name: newAdminName,
                                            username: newAdminUser,
                                            password: newAdminPass,
                                            accessTabs: newAdminAccess,
                                          }
                                        : a,
                                    ),
                                  );
                                } else {
                                  const newAdmin: AdminAccount = {
                                    id: Date.now().toString(),
                                    name: newAdminName,
                                    username: newAdminUser,
                                    password: newAdminPass,
                                    accessTabs: newAdminAccess,
                                  };
                                  setAdminAccounts([
                                    ...adminAccounts,
                                    newAdmin,
                                  ]);
                                }
                                setNewAdminName("");
                                setNewAdminUser("");
                                setNewAdminPass("");
                                setNewAdminAccess([]);
